#include<bits/stdc++.h>
using namespace std;
const int maxn = 1e5+5;
long long c[5],n,d[5],s,dp[maxn];
int main()
{
	for(int i=1;i<=4;i++)cin>>c[i];cin>>n;
	dp[0]=1;
	for(int i=1;i<=4;i++)
	{
		for(int j=c[i];j<=100000;j++)
		dp[j]+=dp[j-c[i]];
	}
	while(n--)
	{
		for(int i=1;i<=4;i++)cin>>d[i];cin>>s;
		long long ans=dp[s];
		for(int i=1;i<=15;i++)
		{
			long long k=0,cnt=0;
			for(int j=0;j<4;j++)
			{
				int p=j+1;
				if(i&(1<<j))
				{
					cnt++;
					k+=c[p]*(d[p]+1);
				}
			}
			long long f=1;
			if(cnt%2)f=-1;
			if(s>=k)ans+=f*dp[s-k];
		}
		cout<<ans<<endl; 
	}
	return 0;
}
